1	type Item = { type: string };
2	type ScenarioInput = { steps: { items: Item[] }[] };
3	
4	const PROCESSING_FEE = 5;
5	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
6	const COMPONENT_BASE = 25;
7	const COMPONENT_BLOCK_BASE = 60;
8	const COMPONENT_BLOCK_SIZE = 3;
9	const ITEM_BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	};
15	
16	function policyBase(items: Item[]): number {
17	  const components: Record<string, number> = {};
18	  let base = 0;
19	  for (const item of items) {
20	    if (COMPONENT_TYPES.has(item.type)) {
21	      components[item.type] = (components[item.type] ?? 0) + 1;
22	    } else {
23	      base += ITEM_BASE_PREMIUM[item.type];
24	    }
25	  }
26	  for (const count of Object.values(components)) {
27	    base += count === COMPONENT_BLOCK_SIZE
28	      ? COMPONENT_BLOCK_BASE
29	      : count * COMPONENT_BASE;
30	  }
31	  return base;
32	}
33	
34	export function runScenario(input: unknown): unknown {
35	  const { steps: [{ items }] } = input as ScenarioInput;
36	  if (items.length === 0) {
37	    return { results: [{ premium: PROCESSING_FEE }] };
38	  }
39	  const base = policyBase(items);
40	  // Use integer tenths to avoid float drift: base + 10% = base * 11 / 10
41	  const tenths = base * 11;
42	  const premium = Math.ceil(tenths / 10) + PROCESSING_FEE;
43	  return { results: [{ premium }] };
44	}
