export function runScenario(input: unknown): unknown {
  const { steps: [{ items }] } = input as ScenarioInput;
  const base = policyBase(items);
  // Apply first-insurance 10% via integer tenths to avoid float drift,
  // then round up and add the flat processing fee.
  const premium = Math.ceil((base * 11) / 10) + PROCESSING_FEE;
  return { results: [{ premium }] };
}
